import React, { useContext, useEffect } from 'react';
import PlanetsContext from '../contexts/PlanetsContext';
import Loading from './Loading';

function Table() {
  const { loading, planets, getPlanets } = useContext(PlanetsContext);

  useEffect(() => {
    getPlanets();
    // eslint-disable-next-line
  }, []);

  const tableTitles = [
    'Name',
    'Rotation Period',
    'Orbital Period',
    'Diameter',
    'Climate',
    'Gravity',
    'Terrain',
    'Surface Water',
    'Population',
    'Films',
    'Created',
    'Edited',
    'URL',
  ];

  return (
    loading ? <Loading /> : (
      <table>
        <thead>
          {tableTitles.map((titles) => (<th key={ titles }>{ titles }</th>))}
        </thead>
        <tbody>
          {planets && planets.map((info) => (
            <tr key={ info.name }>
              <td>{info.name}</td>
              <td>{info.rotation_period}</td>
              <td>{info.orbital_period}</td>
              <td>{info.diameter}</td>
              <td>{info.climate}</td>
              <td>{info.gravity}</td>
              <td>{info.terrain}</td>
              <td>{info.surface_water}</td>
              <td>{info.population}</td>
              <td>{info.films.map((film) => <p key={ film }>{ film }</p>)}</td>
              <td>{info.created}</td>
              <td>{info.edited}</td>
              <td>{info.url}</td>
            </tr>
          ))}
        </tbody>
      </table>
    )
  // <p>Requisição concluida</p>
  );
}

export default Table;
